    85→    private readonly int _dispatcherCount;
    86→    private readonly Channel<EventEnvelope> _channel;
    87→    private readonly CancellationTokenSource _cts = new();
    88→    private readonly Task[] _dispatchers;
    89→
    90→    // Map: EventType -> (SubscriberId -> Subscription)
    91→    private readonly ConcurrentDictionary<Type,
    92→        ConcurrentDictionary<string, Subscription>> _subscriptions = new();
    93→
    94→    // Used when the caller does not specify a subscriberId.
