    96→
    97→    private bool _disposed;
    98→
    99→    /// <summary>
   100→    /// Creates a new instance with the provided logger. Dispatcher thread-count
   101→    /// defaults to <c>Environment.ProcessorCount</c>.
   102→    /// </summary>
