   104→        ILogger<InMemoryEventBus> logger,
   105→        int? dispatcherCount = null,
   106→        int channelCapacity = 65_536)
   107→    {
   108→        _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   109→
   110→        _dispatcherCount = dispatcherCount is > 0 ? dispatcherCount.Value : Environment.ProcessorCount;
   111→        var options = new BoundedChannelOptions(channelCapacity)
   112→        {
   113→            SingleReader = false,
   114→            SingleWriter = false,
   115→            FullMode = BoundedChannelFullMode.Wait
   116→        };
