   118→
   119→        // Spin up background dispatcher tasks.
   120→        _dispatchers = new Task[_dispatcherCount];
   121→        for (var i = 0; i < _dispatcherCount; i++)
   122→        {
   123→            _dispatchers[i] = Task.Factory.StartNew(
   124→                () => DispatcherLoop(i, _cts.Token),
   125→                _cts.Token,
   126→                TaskCreationOptions.LongRunning,
   127→                TaskScheduler.Default);
   128→        }
