   134→
   135→    // ---------------------------------------------------------------------
   136→    // IEventBus implementation
   137→    // ---------------------------------------------------------------------
   138→
   139→    public IDisposable Subscribe<TEvent>(
   140→        Func<TEvent, CancellationToken, ValueTask> handler,
   141→        string? subscriberId = null)
   142→        where TEvent : IEvent
   143→    {
