   557→    // Simple compound APR strategy with 12-second block time assumption
   558→    public sealed class DefaultRewardCalculator : IRewardCalculatorStrategy
   559→    {
   560→        private const decimal Apr = 0.08m; // 8% APR
   561→
   562→        public decimal Calculate(object accountObj, DateTimeOffset now)
   563→        {
   564→            if (accountObj is not StakingService.StakeAccount account)
   565→                throw new ArgumentException(nameof(accountObj));
   566→
   567→            var secondsYear = 365 * 24 * 60 * 60;
   568→            var accrued     = 0m;
   569→
   570→            foreach (var stakeInfo in account.ListStakes())
   571→            {
   572→                if (stakeInfo.State == StakeState.Withdrawn)
   573→                    continue;
   574→
   575→                var durationSeconds = (decimal)(now - stakeInfo.CreatedAt).TotalSeconds;
   576→                accrued += stakeInfo.Amount * (Apr * durationSeconds / secondsYear);
   577→            }
   578→
   579→            return Math.Round(accrued - account.RewardsClaimed, 8);
   580→        }
   581→    }
