    24→/// <summary>
    25→///     Central orchestrator for on-chain governance.
    26→///     Handles proposal lifecycle, voting logic, and policy enforcement.
    27→///     Thread-safe and event-driven.
    28→/// </summary>
    29→/// <remarks>
    30→///     NOTE: This implementation keeps state in-memory. In production, persist proposals and votes to durable storage.
    31→/// </remarks>
    32→public sealed class GovernanceService : IGovernanceService, IDisposable
    33→{
    34→    private readonly ConcurrentDictionary<Guid, ProposalAggregate> _proposals = new();
    35→    private readonly IEnumerable<IGovernancePolicy>               _policies;
    36→    private readonly IEventBus                                     _eventBus;
    37→    private readonly ISystemClock                                  _clock;
    38→    private readonly ReaderWriterLockSlim                          _lifecycleLock = new();
    39→
    40→    private bool _disposed;
    41→
    42→    public GovernanceService(
    43→        IEnumerable<IGovernancePolicy> policies,
    44→        IEventBus                      eventBus,
    45→        ISystemClock                   clock)
    46→    {
    47→        _policies  = policies ?? throw new ArgumentNullException(nameof(policies));
    48→        _eventBus  = eventBus ?? throw new ArgumentNullException(nameof(eventBus));
    49→        _clock     = clock   ?? throw new ArgumentNullException(nameof(clock));
    50→
    51→        // Hook up reactive listeners (Observer pattern) for downstream services
    52→        _eventBus.Subscribe<ProposalCreatedEvent>(OnProposalCreatedAsync);
    53→        _eventBus.Subscribe<ProposalFinalizedEvent>(OnProposalFinalizedAsync);
    54→    }
    55→
    56→    #region IGovernanceService
    57→
    58→    public Proposal CreateProposal(CreateProposalRequest request, CancellationToken ct = default)
    59→    {
    60→        ThrowIfDisposed();
    61→
    62→        if (request is null) throw new ArgumentNullException(nameof(request));
    63→
    64→        var proposal = new Proposal(
    65→            Guid.NewGuid(),
    66→            request.Title.Trim(),
    67→            request.Description.Trim(),
    68→            _clock.UtcNow,
    69→            request.VotingDeadline,
    70→            ProposalStatus.Pending);
    71→
    72→        if (!_policies.All(p => p.ValidateProposal(proposal)))
    73→            throw new GovernanceException("One or more policies rejected the proposal.");
    74→
    75→        var aggregate = new ProposalAggregate(proposal);
    76→
    77→        if (!_proposals.TryAdd(proposal.Id, aggregate))
    78→            throw new InvalidOperationException($"Proposal ID collision occurred: {proposal.Id}");
    79→
    80→        _eventBus.Publish(new ProposalCreatedEvent(proposal));
    81→
    82→        return proposal;
    83→    }
    84→
    85→    public VoteReceipt CastVote(Guid proposalId, VoteType voteType, string voterAddress, CancellationToken ct = default)
    86→    {
    87→        ThrowIfDisposed();
    88→
    89→        if (string.IsNullOrWhiteSpace(voterAddress))
    90→            throw new ArgumentException("Voter address must be provided.", nameof(voterAddress));
    91→
    92→        if (!_proposals.TryGetValue(proposalId, out var aggregate))
    93→            throw new ProposalNotFoundException(proposalId);
    94→
    95→        _lifecycleLock.EnterUpgradeableReadLock();
    96→        try
    97→        {
    98→            if (aggregate.Proposal.Status is ProposalStatus.Finalized)
    99→                throw new GovernanceException("Voting period has ended for this proposal.");
   100→
   101→            if (aggregate.Proposal.VotingDeadline <= _clock.UtcNow)
   102→            {
   103→                // Attempt to finalize asynchronously—do not block caller
   104→                _ = Task.Run(() => FinalizeAsync(aggregate, default), ct);
   105→                throw new GovernanceException("Voting period has already elapsed.");
   106→            }
   107→
   108→            var vote = new Vote(
   109→                aggregate.Proposal.Id,
   110→                voterAddress,
   111→                voteType,
   112→                _clock.UtcNow);
   113→
   114→            if (aggregate.HasVoted(voterAddress))
   115→                throw new GovernanceException("Voter has already cast a vote on this proposal.");
   116→
   117→            if (!_policies.All(p => p.ValidateVote(aggregate.Proposal, vote)))
   118→                throw new GovernanceException("One or more policies rejected the vote.");
   119→
   120→            _lifecycleLock.EnterWriteLock();
   121→            try
   122→            {
   123→                aggregate.AddVote(vote);
   124→            }
   125→            finally
   126→            {
   127→                _lifecycleLock.ExitWriteLock();
   128→            }
   129→
   130→            _eventBus.Publish(new VoteCastEvent(vote));
   131→
   132→            return new VoteReceipt(vote, aggregate.Tally());
   133→        }
   134→        finally
   135→        {
   136→            _lifecycleLock.ExitUpgradeableReadLock();
   137→        }
   138→    }
   139→
   140→    public ProposalTally GetCurrentTally(Guid proposalId)
   141→    {
   142→        ThrowIfDisposed();
   143→
   144→        if (!_proposals.TryGetValue(proposalId, out var aggregate))
   145→            throw new ProposalNotFoundException(proposalId);
   146→
   147→        return aggregate.Tally();
   148→    }
   149→
   150→    public IEnumerable<Proposal> ListProposals(ProposalStatus? status = null)
   151→    {
   152→        ThrowIfDisposed();
   153→
   154→        return _proposals.Values
   155→                         .Select(a => a.Proposal)
   156→                         .Where(p => status is null || p.Status == status)
   157→                         .OrderByDescending(p => p.CreatedAt)
   158→                         .ToList(); // Materialize enumeration for thread-safety
   159→    }
