   163→    #region Event Handlers
   164→
   165→    private Task OnProposalCreatedAsync(ProposalCreatedEvent @event)
   166→    {
   167→        // Additional cross-cutting behavior could be executed here
   168→        // e.g., update search index, notify users, log analytics, etc.
   169→        return Task.CompletedTask;
   170→    }
   171→
   172→    private async Task OnProposalFinalizedAsync(ProposalFinalizedEvent @event)
   173→    {
   174→        // Dispatch post-finalization hooks in parallel
   175→        var tasks = _policies.Select(p => p.OnProposalFinalizedAsync(@event.Proposal, @event.Tally));
   176→        await Task.WhenAll(tasks).ConfigureAwait(false);
   177→    }
   178→
   179→    #endregion
   180→
   181→    #region Lifecycle
   182→
   183→    private async Task FinalizeAsync(ProposalAggregate aggregate, CancellationToken ct)
   184→    {
   185→        _lifecycleLock.EnterWriteLock();
   186→        try
   187→        {
   188→            if (aggregate.Proposal.Status is ProposalStatus.Finalized)
   189→                return; // Idempotent
   190→
   191→            var tally = aggregate.Tally();
   192→
   193→            var decision = _policies
   194→                .Select(p => p.EvaluateResult(aggregate.Proposal, tally))
   195→                .Aggregate(ProposalDecision.Undecided, CombineDecisions);
   196→
   197→            aggregate.Finalize(_clock.UtcNow, decision);
   198→
   199→            _eventBus.Publish(new ProposalFinalizedEvent(aggregate.Proposal, tally));
   200→        }
   201→        finally
   202→        {
   203→            _lifecycleLock.ExitWriteLock();
   204→        }
   205→
   206→        await Task.CompletedTask;
   207→    }
   208→
   209→    private static ProposalDecision CombineDecisions(ProposalDecision first, ProposalDecision second)
   210→    {
   211→        // If any policy rejects, the proposal is rejected.
   212→        if (first == ProposalDecision.Rejected || second == ProposalDecision.Rejected)
   213→            return ProposalDecision.Rejected;
   214→
   215→        // If any policy approves and none reject, approved.
   216→        if (first == ProposalDecision.Approved || second == ProposalDecision.Approved)
   217→            return ProposalDecision.Approved;
   218→
   219→        return ProposalDecision.Undecided;
   220→    }
   221→
   222→    #endregion
   223→
   224→    #region IDisposable
   225→
   226→    public void Dispose()
   227→    {
   228→        if (_disposed) return;
   229→
   230→        _lifecycleLock.Dispose();
   231→        _disposed = true;
   232→        GC.SuppressFinalize(this);
   233→    }
   234→
   235→    [MemberNotNull(nameof(_lifecycleLock))]
   236→    private void ThrowIfDisposed()
   237→    {
   238→        if (_disposed)
   239→            throw new ObjectDisposedException(nameof(GovernanceService));
   240→    }
   241→
   242→    #endregion
   243→}
