   380→/// <summary>
   381→///     Default simple-majority policy.
   382→///     Accepts proposal if YES > NO at the end of voting deadline.
   383→///     Requires a minimum turnout of 1 vote.
   384→/// </summary>
   385→public sealed class SimpleMajorityPolicy : IGovernancePolicy
   386→{
   387→    public bool ValidateProposal(Proposal proposal)
   388→    {
   389→        if (proposal.VotingDeadline <= proposal.CreatedAt)
   390→            return false; // Deadline must be in the future
   391→
   392→        if (proposal.VotingDeadline - proposal.CreatedAt < TimeSpan.FromHours(1))
   393→            return false; // At least 1 hour voting window
   394→
   395→        return true;
   396→    }
   397→
   398→    public bool ValidateVote(Proposal proposal, Vote vote)
   399→    {
   400→        // Additional anti-sybil or stake-weight checks could be inserted here
   401→        return true;
   402→    }
   403→
   404→    public ProposalDecision EvaluateResult(Proposal proposal, ProposalTally tally)
   405→    {
   406→        if (tally.Total == 0)
   407→            return ProposalDecision.Rejected; // No participation → reject
