    17→namespace UtilityChain.Networking;
    18→
    19→/// <summary>
    20→///     High-level service responsible for peer-to-peer networking.  The service boots a <see cref="TcpListener"/>
    21→///     to accept inbound connections, dials out to seed peers, and performs a minimal handshake
    22→///     (UtilityChain version / network-id exchange).  Once a peer is authenticated it is tracked in
    23→///     <see cref="_peers"/> and participates in broadcast / gossip operations through an
    24→///     internal channel pump.
    25→/// </summary>
    26→public sealed class P2PService : BackgroundService, IP2PService, IDisposable
    27→{
    28→    private const int HandshakeTimeoutSeconds = 5;
    29→    private const int ReceiveBufferSize      = 32 * 1024; // 32KiB reasonable default
    30→    private const int SendBufferSize         = 32 * 1024;
    31→
    32→    private readonly ILogger<P2PService>               _logger;
    33→    private readonly P2PSettings                       _settings;
    34→    private readonly IEventBus                         _eventBus;
    35→    private readonly TcpListener                       _listener;
    36→    private readonly ConcurrentDictionary<string, PeerConnection> _peers;
    37→    private readonly Channel<OutboundEnvelope>         _outbound; // Multiplexer for all outbound messages
    38→
    39→    private bool _disposed;
    40→
    41→    public P2PService(
    42→        ILogger<P2PService> logger,
    43→        P2PSettings settings,
    44→        IEventBus eventBus)
    45→    {
    46→        _logger    = logger  ?? throw new ArgumentNullException(nameof(logger));
    47→        _settings  = settings ?? throw new ArgumentNullException(nameof(settings));
    48→        _eventBus  = eventBus ?? throw new ArgumentNullException(nameof(eventBus));
    49→
    50→        // Data structures
    51→        _peers    = new ConcurrentDictionary<string, PeerConnection>(StringComparer.Ordinal);
    52→        _outbound = Channel.CreateUnbounded<OutboundEnvelope>(new UnboundedChannelOptions
    53→        {
    54→            SingleReader = true,
    55→            SingleWriter = false
    56→        });
    57→
    58→        // Network listener
    59→        _listener = new TcpListener(IPAddress.Any, _settings.Port)
    60→        {
    61→            Server =
    62→            {
    63→                NoDelay         = true,
    64→                ReceiveBufferSize = ReceiveBufferSize,
    65→                SendBufferSize    = SendBufferSize
    66→            }
    67→        };
    68→    }
    69→
    70→    #region BackgroundService overrides
    71→
    72→    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    73→    {
    74→        _logger.LogInformation("P2PService starting on port {Port}", _settings.Port);
    75→        _listener.Start();
    76→
    77→        // Kick off parallel tasks
    78→        var acceptLoop    = AcceptLoopAsync(stoppingToken);
    79→        var outboundLoop  = OutboundPumpAsync(stoppingToken);
    80→        var seedDialLoop  = DialSeedsAsync(stoppingToken);
    81→
    82→        await Task.WhenAll(acceptLoop, outboundLoop, seedDialLoop).ConfigureAwait(false);
    83→    }
    84→
    85→    public override async Task StopAsync(CancellationToken cancellationToken)
    86→    {
    87→        _logger.LogInformation("P2PService stopping…");
    88→
    89→        _listener.Stop();
    90→
    91→        foreach (var (_, peer) in _peers)
    92→        {
    93→            peer.Dispose();
    94→        }
    95→
    96→        // Ensure channel completes to flush outbound pump
    97→        _outbound.Writer.TryComplete();
    98→
    99→        await base.StopAsync(cancellationToken).ConfigureAwait(false);
   100→    }
