   104→    #region Accept / Dial
   105→
   106→    private async Task AcceptLoopAsync(CancellationToken ct)
   107→    {
   108→        while (!ct.IsCancellationRequested)
   109→        {
   110→            try
   111→            {
   112→                var client = await _listener.AcceptTcpClientAsync(ct).ConfigureAwait(false);
   113→                _ = HandleNewConnectionAsync(client, ct);
   114→            }
   115→            catch (OperationCanceledException)
   116→            {
   117→                // Service is shutting down
   118→            }
   119→            catch (Exception ex)
   120→            {
   121→                _logger.LogWarning(ex, "Unexpected error in accept loop.");
   122→            }
   123→        }
   124→    }
