   126→    private async Task DialSeedsAsync(CancellationToken ct)
   127→    {
   128→        foreach (var seed in _settings.SeedNodes)
   129→        {
   130→            if (ct.IsCancellationRequested) break;
   131→
   132→            try
   133→            {
   134→                await DialAsync(seed, ct).ConfigureAwait(false);
   135→            }
   136→            catch (Exception ex)
   137→            {
   138→                _logger.LogDebug(ex, "Failed to dial seed {Seed}", seed);
