   143→    private async Task DialAsync(IPEndPoint endPoint, CancellationToken ct)
   144→    {
   145→        if (_peers.ContainsKey(endPoint.ToString())) return;
   146→
   147→        using var client = new TcpClient
   148→        {
   149→            NoDelay          = true,
   150→            ReceiveBufferSize = ReceiveBufferSize,
   151→            SendBufferSize    = SendBufferSize
   152→        };
   153→
   154→        await client.ConnectAsync(endPoint, ct).ConfigureAwait(false);
   155→        await HandleNewConnectionAsync(client, ct, outboundInitiator: true).ConfigureAwait(false);
   156→    }
