   158→    #endregion
   159→
   160→    #region Connection handler
   161→
   162→    private async Task HandleNewConnectionAsync(
   163→        TcpClient client,
   164→        CancellationToken ct,
   165→        bool outboundInitiator = false)
   166→    {
   167→        var remoteEndPoint = client.Client.RemoteEndPoint?.ToString();
   168→        if (remoteEndPoint == null)
   169→        {
   170→            client.Dispose();
   171→            return;
   172→        }
   173→
   174→        // Enforce peer limit
   175→        if (_peers.Count >= _settings.MaxPeers)
   176→        {
   177→            _logger.LogDebug("Rejecting {Peer} – peer limit reached.", remoteEndPoint);
   178→            client.Close();
   179→            return;
   180→        }
   181→
   182→        NetworkStream stream = client.GetStream();
   183→
   184→        var peer = new PeerConnection(client, stream, _settings, _logger);
   185→        if (!_peers.TryAdd(remoteEndPoint, peer))
   186→        {
   187→            client.Close();
   188→            return;
   189→        }
   190→
   191→        _logger.LogInformation(
   192→            "Peer {Peer} {Direction}",
   193→            remoteEndPoint,
   194→            outboundInitiator ? "dialed" : "connected");
   195→
   196→        try
   197→        {
   198→            // Perform handshake
   199→            using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(HandshakeTimeoutSeconds));
   200→            using var linkedCts = CancellationTokenSource.CreateLinkedTokenSource(ct, cts.Token);
   201→
   202→            await DoHandshakeAsync(peer, outboundInitiator, linkedCts.Token).ConfigureAwait(false);
   203→
   204→            // Start receive loop
   205→            _ = ReceiveLoopAsync(peer, ct);
   206→        }
   207→        catch (Exception ex)
   208→        {
   209→            _logger.LogDebug(ex, "Handshake with {Peer} failed.", remoteEndPoint);
   210→            DropPeer(remoteEndPoint);
   211→        }
   212→    }
   213→
   214→    private async Task DoHandshakeAsync(PeerConnection peer, bool outboundInitiator, CancellationToken ct)
   215→    {
   216→        // Build handshake payload
   217→        var hello = new HelloPayload
   218→        {
   219→            NodeId    = _settings.NodeId,
   220→            NetworkId = _settings.NetworkId,
   221→            Timestamp = DateTimeOffset.UtcNow.ToUnixTimeSeconds(),
   222→            Version   = _settings.ProtocolVersion,
   223→            Services  = _settings.Services
   224→        };
   225→
   226→        if (outboundInitiator)
   227→        {
   228→            await peer.SendAsync(hello, ct).ConfigureAwait(false);
   229→            var remoteHello = await peer.ReceiveAsync<HelloPayload>(ct).ConfigureAwait(false);
   230→            ValidateHandshake(remoteHello);
   231→        }
   232→        else
   233→        {
   234→            var remoteHello = await peer.ReceiveAsync<HelloPayload>(ct).ConfigureAwait(false);
   235→            ValidateHandshake(remoteHello);
   236→            await peer.SendAsync(hello, ct).ConfigureAwait(false);
   237→        }
   238→
   239→        peer.IsReady = true;
   240→        _eventBus.Publish(new PeerConnectedEvent(peer.ToPeerInfo()));
   241→    }
   242→
   243→    private void ValidateHandshake(HelloPayload remoteHello)
   244→    {
   245→        if (remoteHello.NetworkId != _settings.NetworkId)
   246→            throw new InvalidDataException($"Network mismatch. Local={_settings.NetworkId}, Remote={remoteHello.NetworkId}");
   247→
   248→        if (remoteHello.Version != _settings.ProtocolVersion)
   249→            _logger.LogWarning("Protocol version mismatch. Local={Local}, Remote={Remote}",
   250→                _settings.ProtocolVersion, remoteHello.Version);
   251→    }
