   253→    #endregion
   254→
   255→    #region Receive / Broadcast
   256→
   257→    private async Task ReceiveLoopAsync(PeerConnection peer, CancellationToken ct)
   258→    {
   259→        try
   260→        {
   261→            while (!ct.IsCancellationRequested && peer.IsReady)
   262→            {
   263→                var header = await peer.ReceiveAsync<MessageHeader>(ct).ConfigureAwait(false);
   264→                var payloadType = MessageRegistry.Resolve(header.Type);
   265→                var payload     = await peer.ReceiveAsync(payloadType, header.Length, ct).ConfigureAwait(false);
   266→
   267→                // Dispatch to event bus
   268→                _eventBus.Publish(new NetworkMessageEvent(peer.ToPeerInfo(), payload));
   269→            }
   270→        }
   271→        catch (IOException)
   272→        {
   273→            // peer closed connection
   274→        }
   275→        catch (OperationCanceledException)
   276→        {
   277→            // shutting down
   278→        }
   279→        catch (Exception ex)
   280→        {
   281→            _logger.LogDebug(ex, "Unexpected error processing peer {Peer}", peer.RemoteEndPoint);
   282→        }
   283→        finally
   284→        {
   285→            DropPeer(peer.RemoteEndPoint);
   286→        }
   287→    }
