   264→/// <summary>
   265→/// Wraps another <see cref="IHostedService"/> and retries it when it exits unexpectedly.
   266→/// This is an application of the proxy pattern providing resilience.
   267→/// </summary>
   268→internal sealed class RetryingHostedServiceDecorator : IHostedService
   269→{
   270→    private readonly IHostedService _inner;
   271→    private readonly ILogger _logger;
   272→    private readonly CancellationTokenSource _cts = new();
   273→
   274→    public RetryingHostedServiceDecorator(IHostedService inner, ILoggerFactory loggerFactory)
   275→    {
   276→        _inner  = inner  ?? throw new ArgumentNullException(nameof(inner));
   277→        _logger = loggerFactory.CreateLogger(inner.GetType().Name + "_RetryDecorator");
   278→    }
   279→
   280→    public async Task StartAsync(CancellationToken cancellationToken)
   281→    {
   282→        _logger.LogDebug("Starting hosted service with retry decorator: {Service}", _inner.GetType().Name);
   283→
   284→        _ = Task.Run(() => RunWithRetryAsync(_cts.Token), CancellationToken.None);
   285→        await Task.CompletedTask;
   286→    }
   287→
   288→    private async Task RunWithRetryAsync(CancellationToken cancellationToken)
   289→    {
   290→        const int maxAttempts = 5;
   291→        var attempt = 0;
   292→
   293→        while (!cancellationToken.IsCancellationRequested)
   294→        {
   295→            try
   296→            {
   297→                attempt++;
   298→                _logger.LogInformation("Attempt {Attempt} to start {Service}.", attempt, _inner.GetType().Name);
   299→
   300→                await _inner.StartAsync(cancellationToken).ConfigureAwait(false);
   301→                _logger.LogInformation("{Service} completed successfully.", _inner.GetType().Name);
   302→                return; // exit loop
   303→            }
   304→            catch (Exception ex) when (attempt < maxAttempts)
   305→            {
   306→                _logger.LogWarning(ex,
   307→                    "{Service} failed with error. Retrying in 5s ({Attempt}/{Max}).",
   308→                    _inner.GetType().Name, attempt, maxAttempts);
   309→
   310→                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken).ConfigureAwait(false);
   311→            }
   312→            catch (Exception ex)
   313→            {
   314→                _logger.LogCritical(ex,
   315→                    "{Service} failed after {MaxAttempts} attempts. Giving up.",
   316→                    _inner.GetType().Name, maxAttempts);
   317→                throw;
   318→            }
   319→        }
   320→    }
   321→
   322→    public async Task StopAsync(CancellationToken cancellationToken)
   323→    {
   324→        _logger.LogDebug("Stopping hosted service with retry decorator: {Service}", _inner.GetType().Name);
   325→
   326→        _cts.Cancel();
   327→        await _inner.StopAsync(cancellationToken).ConfigureAwait(false);
   328→    }
   329→}
