   163→    /// <summary>
   164→    /// Simple in-process event bus leveraging a pub/sub model.
   165→    /// </summary>
   166→    public sealed class InProcessEventBus : IEventBus
   167→    {
   168→        private readonly ConcurrentDictionary<Type, List<Delegate>> _handlers = new();
   169→
   170→        public void Publish<TEvent>(TEvent @event)
   171→        {
   172→            if (_handlers.TryGetValue(typeof(TEvent), out var subscribers))
   173→            {
   174→                foreach (var handler in subscribers.OfType<Action<TEvent>>())
   175→                {
   176→                    // Fire-and-forget; the node is event-driven and
   177→                    // handlers must handle their own exceptions.
   178→                    Task.Run(() => handler(@event));
   179→                }
   180→            }
   181→        }
   182→
   183→        public void Subscribe<TEvent>(Action<TEvent> handler)
   184→        {
   185→            var subscribers = _handlers.GetOrAdd(typeof(TEvent), _ => new List<Delegate>());
   186→            lock (subscribers)
   187→            {
   188→                subscribers.Add(handler);
   189→            }
   190→        }
   191→    }
   192→}
