   262→    /// <summary>
   263→    /// Responsible for discovering and wiring in pluggable node modules.
   264→    /// </summary>
   265→    internal static class ModuleLoader
   266→    {
   267→        public static void LoadModules(
   268→            IServiceCollection services,
   269→            IConfiguration configuration,
   270→            ILogger logger)
   271→        {
   272→            // For simplicity, load all assemblies in the current directory
   273→            // matching the convention `UtilityChain.*.dll`.
   274→            var baseDir   = AppContext.BaseDirectory;
   275→            var assemblies = Directory.EnumerateFiles(baseDir, "UtilityChain.*.dll")
   276→                                      .Select(Assembly.LoadFrom)
   277→                                      .ToArray();
   278→
   279→            foreach (var assembly in assemblies)
   280→            {
   281→                var moduleTypes = assembly
   282→                    .DefinedTypes
   283→                    .Where(t => typeof(INodeModule).IsAssignableFrom(t) &&
   284→                                !t.IsAbstract &&
   285→                                !t.IsInterface)
   286→                    .ToArray();
   287→
   288→                foreach (var moduleType in moduleTypes)
   289→                {
   290→                    try
   291→                    {
   292→                        var module = (INodeModule)Activator.CreateInstance(moduleType)!;
   293→                        module.Register(services, configuration);
   294→                        logger.LogInformation("Loaded module: {Module}", moduleType.FullName);
   295→                    }
   296→                    catch (Exception ex)
   297→                    {
   298→                        logger.LogError(ex, "Failed to load module {Module}", moduleType.FullName);
   299→                    }
   300→                }
   301→            }
   302→        }
   303→    }
   304→}
