     6→//  Description
     7→//  -----------
     8→//  Central in-memory state container and coordinator for the consensus layer.
     9→//  ConsensusContext subscribes to the domain event bus (Observer pattern) and
    10→//  delegates engine-specific work to an interchangeable IConsensusEngine
    11→//  (Strategy + Factory patterns).  It is the single source of truth for the
    12→//  current epoch, slot, validator set, and vote receipts, enabling other
    13→//  modules (staking, governance, API gateway) to interrogate consensus state
    14→//  without directly coupling to the engine implementation.
    15→// -----------------------------------------------------------------------------
    16→
    17→using System;
    18→using System.Collections.Concurrent;
    19→using System.Collections.Generic;
    20→using System.Diagnostics.CodeAnalysis;
    21→using System.Linq;
    22→using System.Threading;
    23→using System.Threading.Tasks;
    24→using Microsoft.Extensions.Logging;
    25→using UtilityChain.Common.Guards;
    26→using UtilityChain.Common.Time;
    27→using UtilityChain.Messaging;
    28→using UtilityChain.Persistence;
    29→
    30→namespace UtilityChain.Consensus;
    31→
    32→/// <summary>
    33→/// Represents the authoritative, thread-safe context object that maintains
    34→/// the volatile consensus state for the running node.  This includes
    35→/// coordination of epochs/slots, vote receipts, validator liveness tracking,
    36→/// and delegated execution of the underlying consensus algorithm.
    37→/// </summary>
    38→public sealed class ConsensusContext : IDisposable
    39→{
    40→    private readonly IConsensusEngine                 _engine;
    41→    private readonly IEventBus                        _eventBus;
    42→    private readonly IStateStore                      _stateStore;
    43→    private readonly ILogger<ConsensusContext>        _logger;
    44→    private readonly ISystemClock                     _clock;
    45→
    46→    private readonly ReaderWriterLockSlim             _stateLock = new();
    47→    private readonly ConcurrentDictionary<Guid, Vote> _pendingVotes = new();
    48→
    49→    // Cancellation/Task management ------------------------------------------------
    50→    private readonly CancellationTokenSource          _cts = new();
    51→    private Task?                                     _backgroundTask;
    52→
    53→    // Internal mutable state ------------------------------------------------------
    54→    private ConsensusState _state;
    55→
    56→    public ConsensusContext(
    57→        IConsensusEngine engine,
    58→        IEventBus eventBus,
    59→        IStateStore stateStore,
    60→        ISystemClock clock,
    61→        ILogger<ConsensusContext> logger)
    62→    {
    63→        _engine     = Guard.NotNull(engine);
    64→        _eventBus   = Guard.NotNull(eventBus);
    65→        _stateStore = Guard.NotNull(stateStore);
    66→        _clock      = Guard.NotNull(clock);
    67→        _logger     = Guard.NotNull(logger);
    68→
    69→        _state = LoadOrCreateInitialState();
    70→    }
    71→
    72→    // -------------------------------------------------------------------------
    73→    //  Lifecycle
    74→    // -------------------------------------------------------------------------
    75→    public void Start()
    76→    {
    77→        _logger.LogInformation("ConsensusContext starting for epoch {Epoch}.", _state.Epoch);
    78→
    79→        // Subscribe to relevant domain events (Observer pattern)
    80→        _eventBus.Subscribe<BlockCommittedEvent>(HandleBlockCommitted);
    81→        _eventBus.Subscribe<VoteReceivedEvent>(HandleVoteReceived);
    82→
    83→        // Kick off background duties (e.g. slot timer)
    84→        _backgroundTask = Task.Factory.StartNew(
    85→            RunSlotLoopAsync,
    86→            _cts.Token,
    87→            TaskCreationOptions.LongRunning,
    88→            TaskScheduler.Default
    89→        ).Unwrap();
    90→    }
    91→
    92→    public async Task StopAsync()
    93→    {
    94→        _logger.LogInformation("ConsensusContext stopping …");
    95→
    96→        _cts.Cancel();
    97→        if (_backgroundTask is not null)
    98→        {
    99→            try
   100→            {
   101→                await _backgroundTask.ConfigureAwait(false);
   102→            }
   103→            catch (OperationCanceledException)
   104→            {
   105→                _logger.LogDebug("Consensus background task canceled.");
   106→            }
   107→            catch (Exception ex)
   108→            {
   109→                _logger.LogError(ex, "Consensus background task stopped with error.");
   110→            }
   111→        }
   112→
   113→        _eventBus.Unsubscribe<BlockCommittedEvent>(HandleBlockCommitted);
   114→        _eventBus.Unsubscribe<VoteReceivedEvent>(HandleVoteReceived);
   115→
   116→        _logger.LogInformation("ConsensusContext stopped.");
   117→    }
   118→
   119→    public void Dispose()
   120→    {
   121→        _cts.Cancel();
   122→        _cts.Dispose();
   123→        _stateLock.Dispose();
   124→    }
   125→
   126→    // -------------------------------------------------------------------------
   127→    //  Public API
   128→    // -------------------------------------------------------------------------
   129→    /// <summary>
   130→    /// Returns a snapshot of the current validator set.
   131→    /// </summary>
   132→    public IReadOnlyList<Validator> GetCurrentValidators()
   133→    {
   134→        _stateLock.EnterReadLock();
   135→        try
   136→        {
   137→            return _state.Validators.ToList();
   138→        }
   139→        finally
   140→        {
   141→            _stateLock.ExitReadLock();
   142→        }
   143→    }
   144→
   145→    /// <summary>
   146→    /// Attempts to retrieve a vote by its identifier from the in-memory cache.
   147→    /// </summary>
   148→    public bool TryGetVote(Guid voteId, [NotNullWhen(true)] out Vote? vote)
   149→        => _pendingVotes.TryGetValue(voteId, out vote);
   150→
   151→    // -------------------------------------------------------------------------
   152→    //  Event Handlers (Observer pattern)
   153→    // -------------------------------------------------------------------------
   154→    private void HandleBlockCommitted(BlockCommittedEvent evt)
   155→    {
   156→        _logger.LogDebug(
   157→            "Block {Height} committed; updating state for epoch {Epoch}.",
   158→            evt.Block.Header.Height,
   159→            _state.Epoch);
   160→
   161→        _stateLock.EnterWriteLock();
   162→        try
   163→        {
   164→            _state = _state with
   165→            {
   166→                LastBlockHash      = evt.Block.Header.Hash,
   167→                LastBlockTimestamp = evt.Block.Header.Timestamp
   168→            };
   169→        }
   170→        finally
   171→        {
   172→            _stateLock.ExitWriteLock();
   173→        }
   174→    }
   175→
   176→    private void HandleVoteReceived(VoteReceivedEvent evt)
   177→    {
   178→        if (_pendingVotes.TryAdd(evt.Vote.Id, evt.Vote))
   179→        {
   180→            _logger.LogTrace("Vote {VoteId} queued from validator {ValidatorId}.",
   181→                evt.Vote.Id,
   182→                evt.Vote.ValidatorId);
   183→        }
   184→    }
   185→
   186→    // -------------------------------------------------------------------------
   187→    //  Slot Loop
   188→    // -------------------------------------------------------------------------
   189→    private async Task RunSlotLoopAsync()
   190→    {
   191→        _logger.LogInformation("Slot loop started.");
   192→        while (!_cts.IsCancellationRequested)
   193→        {
   194→            try
   195→            {
   196→                await ExecuteSlotAsync(_cts.Token).ConfigureAwait(false);
   197→            }
   198→            catch (OperationCanceledException)
   199→            {
   200→                break;
   201→            }
   202→            catch (Exception ex)
   203→            {
   204→                _logger.LogError(ex, "Error executing consensus slot.");
   205→            }
   206→        }
   207→
   208→        _logger.LogInformation("Slot loop exited.");
   209→    }
   210→
   211→    private async Task ExecuteSlotAsync(CancellationToken ct)
   212→    {
   213→        ConsensusState snapshot;
   214→        _stateLock.EnterReadLock();
   215→        try
   216→        {
   217→            snapshot = _state;
   218→        }
   219→        finally
   220→        {
   221→            _stateLock.ExitReadLock();
   222→        }
   223→
   224→        var slotStart   = _clock.UtcNow;
   225→        var slotEnd     = slotStart.Add(snapshot.SlotDuration);
   226→
   227→        _logger.LogDebug("Executing slot {Slot} of epoch {Epoch}.", snapshot.SlotIndex, snapshot.Epoch);
   228→
   229→        // Strategy pattern: delegate to the configured consensus engine
   230→        var result = await _engine.ExecuteSlotAsync(snapshot, ct).ConfigureAwait(false);
   231→
   232→        switch (result)
   233→        {
   234→            case SlotResult.BlockProposed proposal:
   235→                _eventBus.Publish(new BlockProposedEvent(proposal.Block));
   236→                break;
   237→
   238→            case SlotResult.Empty:
   239→                _logger.LogTrace("Slot {Slot} completed with no block proposal.", snapshot.SlotIndex);
   240→                break;
   241→        }
   242→
   243→        // Rotate to next slot
   244→        _stateLock.EnterWriteLock();
   245→        try
   246→        {
   247→            var nextSlot = (snapshot.SlotIndex + 1) % snapshot.SlotsPerEpoch;
   248→            var epoch    = snapshot.Epoch + (nextSlot == 0 ? 1UL : 0UL);
   249→
   250→            _state = snapshot with
   251→            {
   252→                SlotIndex   = nextSlot,
   253→                Epoch       = epoch,
   254→                SlotStarted = slotStart
   255→            };
   256→        }
   257→        finally
   258→        {
   259→            _stateLock.ExitWriteLock();
   260→        }
   261→
   262→        var delay = slotEnd - _clock.UtcNow;
   263→        if (delay > TimeSpan.Zero)
   264→        {
   265→            await Task.Delay(delay, ct).ConfigureAwait(false);
   266→        }
   267→    }
   268→
   269→    // -------------------------------------------------------------------------
   270→    //  Private helpers
   271→    // -------------------------------------------------------------------------
   272→    private ConsensusState LoadOrCreateInitialState()
   273→    {
   274→        try
   275→        {
   276→            var persisted = _stateStore.Get<ConsensusState>("ConsensusState");
   277→            if (persisted is not null)
   278→            {
   279→                _logger.LogInformation("Loaded consensus state from persistence.");
   280→                return persisted;
   281→            }
   282→        }
   283→        catch (Exception ex)
   284→        {
   285→            _logger.LogWarning(ex, "Unable to load persisted consensus state. Falling back to default.");
   286→        }
   287→
   288→        // Defaults for a newly bootstrapped chain
   289→        var genesisValidators = _stateStore.Get<IReadOnlyList<Validator>>("GenesisValidators")
   290→                               ?? Array.Empty<Validator>();
   291→
   292→        return new ConsensusState(
   293→            epoch:               0UL,
   294→            slotIndex:           0,
   295→            slotsPerEpoch:       64,
   296→            slotDuration:        TimeSpan.FromSeconds(3),
   297→            validators:          genesisValidators,
   298→            lastBlockHash:       null,
   299→            lastBlockTimestamp:  DateTimeOffset.MinValue,
   300→            slotStarted:         _clock.UtcNow
   301→        );
   302→    }
   303→
   304→    // -------------------------------------------------------------------------
   305→    //  Data/DTO records
   306→    // -------------------------------------------------------------------------
   307→    private sealed record ConsensusState(
   308→        ulong               Epoch,
   309→        int                 SlotIndex,
   310→        int                 SlotsPerEpoch,
   311→        TimeSpan            SlotDuration,
   312→        IReadOnlyList<Validator> Validators,
   313→        string?             LastBlockHash,
   314→        DateTimeOffset      LastBlockTimestamp,
   315→        DateTimeOffset      SlotStarted);
   316→
   317→    public sealed record Validator(
   318→        string             Id,
   319→        string             PublicKey,
   320→        bool               IsActive,
   321→        ulong              Stake);
   322→
   323→    // -------------------------------------------------------------------------
   324→    //  Event payloads (internal to ConsensusContext for brevity)
   325→    // -------------------------------------------------------------------------
   326→    public sealed record BlockCommittedEvent(Block Block);
   327→    public sealed record BlockProposedEvent(Block Block);
   328→    public sealed record VoteReceivedEvent(Vote Vote);
   329→
   330→    // -------------------------------------------------------------------------
   331→    //  Simplified stand-in types
   332→    // -------------------------------------------------------------------------
   333→    public sealed record Vote(Guid Id, string ValidatorId, byte[] Signature);
   334→    public sealed record Block(BlockHeader Header);
   335→
   336→    public sealed record BlockHeader(
   337→        ulong            Height,
   338→        string           Hash,
   339→        DateTimeOffset   Timestamp);
   340→
   341→    // -------------------------------------------------------------------------
   342→    //  Slot execution results
   343→    // -------------------------------------------------------------------------
   344→    public abstract record SlotResult
   345→    {
   346→        public sealed record BlockProposed(Block Block) : SlotResult;
   347→        public sealed record Empty                      : SlotResult;
   348→    }
   349→}
