    25→    {
    26→        private readonly ITokenRepository           _repository;
    27→        private readonly IEventBus                  _eventBus;
    28→        private readonly ITokenStandardFactory      _standardFactory;
    29→        private readonly ILogger<TokenService>      _logger;
    30→        
    31→        //   Extremely light-weight cache for hot token instances.
    32→        private readonly ConcurrentDictionary<TokenId, ITokenStandardStrategy> _strategies = new();
    33→
    34→        //   Used to avoid double-registration with the event bus.
    35→        private int _isSubscribedToBlockEvents;
