    51→        public async Task<TokenId> CreateTokenAsync(CreateTokenRequest request, CancellationToken ct = default)
    52→        {
    53→            ArgumentNullException.ThrowIfNull(request);
    54→
    55→            var tokenId = TokenId.New();
    56→            
    57→            ITokenStandardStrategy strategy = _standardFactory.Create(request.Standard, tokenId, request.Metadata);
    58→
    59→            //  Save token metadata & initial state.
    60→            await _repository.AddTokenAsync(strategy.Descriptor, ct).ConfigureAwait(false);
    61→            _strategies[tokenId] = strategy;
    62→
    63→            _eventBus.Publish(new TokenCreatedEvent(tokenId, request.Owner, request.Standard));
    64→
    65→            _logger.LogInformation("Created token {TokenId} ({Standard}) by {Owner}", tokenId, request.Standard, request.Owner);
    66→            EnsureBlockSubscription();
    67→            return tokenId;
    68→        }
