    70→        public Task MintAsync(TokenId tokenId, Address to, ulong amount, CancellationToken ct = default)
    71→            => ExecuteAsync(tokenId, strategy => strategy.MintAsync(to, amount, ct), ct);
    72→
    73→        public Task BurnAsync(TokenId tokenId, Address from, ulong amount, CancellationToken ct = default)
    74→            => ExecuteAsync(tokenId, strategy => strategy.BurnAsync(from, amount, ct), ct);
    75→
    76→        public Task TransferAsync(TokenId tokenId, Address from, Address to, ulong amount, CancellationToken ct = default)
    77→            => ExecuteAsync(tokenId, strategy => strategy.TransferAsync(from, to, amount, ct), ct);
    78→
