    82→        public async Task<TokenDescriptor?> GetTokenDescriptorAsync(TokenId tokenId, CancellationToken ct = default)
    83→        {
    84→            if (_strategies.TryGetValue(tokenId, out var existing))
    85→                return existing.Descriptor;
    86→
    87→            var descriptor = await _repository.TryGetTokenAsync(tokenId, ct).ConfigureAwait(false);
