    95→        private void EnsureBlockSubscription()
    96→        {
    97→            if (Interlocked.Exchange(ref _isSubscribedToBlockEvents, 1) == 1) return;
    98→            _eventBus.Subscribe<BlockMinedEvent>(this);
    99→        }
