   103→        public void OnError(Exception error)
   104→            => _logger.LogError(error, "Error while observing BlockMined events.");
   105→
   106→        public async void OnNext(BlockMinedEvent value)
   107→        {
   108→            try
   109→            {
   110→                // Persist any dirty balances periodically to durable storage
   111→                foreach (var strategy in _strategies.Values)
   112→                    await strategy.CommitAsync().ConfigureAwait(false);
   113→            }
   114→            catch (Exception ex)
   115→            {
   116→                _logger.LogError(ex, "Failed to flush token state after block {BlockHeight}", value.Height);
   117→            }
   118→        }
