   124→        private async Task<T> ExecuteAsync<T>(TokenId tokenId, Func<ITokenStandardStrategy, Task<T>> action, CancellationToken ct)
   125→        {
   126→            ITokenStandardStrategy strategy = await ResolveStrategyAsync(tokenId, ct).ConfigureAwait(false);
   127→            T result = await action(strategy).ConfigureAwait(false);
   128→            return result;
   129→        }
   130→
   131→        private async Task<ITokenStandardStrategy> ResolveStrategyAsync(TokenId tokenId, CancellationToken ct)
   132→        {
   133→            if (_strategies.TryGetValue(tokenId, out var existing))
   134→                return existing;
   135→
   136→            TokenDescriptor descriptor = await _repository
   137→                .TryGetTokenAsync(tokenId, ct)
   138→                .ConfigureAwait(false)
   139→                ?? throw new TokenNotFoundException(tokenId);
   140→
   141→            var strategy = _standardFactory.Create(
   142→                descriptor.Standard,
   143→                descriptor.TokenId,
   144→                descriptor.Metadata);
   145→
   146→            _strategies[tokenId] = strategy;
   147→            return strategy;
   148→        }
