   152→        public void Dispose()
   153→        {
   154→            _eventBus.Unsubscribe<BlockMinedEvent>(this);
   155→            foreach (var strategy in _strategies.Values)
   156→                (strategy as IDisposable)?.Dispose();
   157→        }
   158→    }
