   236→    internal sealed class FungibleTokenStrategy : ITokenStandardStrategy
   237→    {
   238→        private readonly TokenDescriptor                        _descriptor;
   239→        private readonly ITokenRepository                       _repository;
   240→        private readonly IEventBus                              _eventBus;
   241→        private readonly ConcurrentDictionary<Address, ulong>   _balances = new();
   242→        private readonly ILogger<FungibleTokenStrategy>         _logger;
   243→
   244→        public FungibleTokenStrategy(
   245→            TokenDescriptor descriptor,
   246→            ITokenRepository repository,
   247→            IEventBus eventBus,
   248→            ILogger<FungibleTokenStrategy> logger)
   249→        {
   250→            _descriptor = descriptor;
   251→            _repository = repository;
   252→            _eventBus   = eventBus;
   253→            _logger     = logger;
   254→        }
   255→
   256→        public TokenDescriptor Descriptor => _descriptor;
   257→
   258→        public async Task MintAsync(Address to, ulong amount, CancellationToken ct)
   259→        {
   260→            _balances.AddOrUpdate(to, amount, (_, existing) => checked(existing + amount));
   261→            _eventBus.Publish(new TokenMintedEvent(_descriptor.TokenId, to, amount));
   262→            await Task.CompletedTask;
   263→        }
   264→
   265→        public async Task BurnAsync(Address from, ulong amount, CancellationToken ct)
   266→        {
   267→            if (!_balances.TryGetValue(from, out var current) || current < amount)
   268→                throw new TokenBalanceException(_descriptor.TokenId, from, current, amount);
   269→
   270→            _balances[from] = current - amount;
   271→            _eventBus.Publish(new TokenBurnedEvent(_descriptor.TokenId, from, amount));
   272→            await Task.CompletedTask;
   273→        }
   274→
   275→        public async Task TransferAsync(Address from, Address to, ulong amount, CancellationToken ct)
   276→        {
   277→            if (!_balances.TryGetValue(from, out var current) || current < amount)
   278→                throw new TokenBalanceException(_descriptor.TokenId, from, current, amount);
   279→
   280→            _balances[from] = current - amount;
   281→            _balances.AddOrUpdate(to, amount, (_, existing) => checked(existing + amount));
   282→            _eventBus.Publish(new TokenTransferredEvent(_descriptor.TokenId, from, to, amount));
   283→            await Task.CompletedTask;
   284→        }
   285→
   286→        public Task<ulong> GetBalanceAsync(Address address, CancellationToken ct)
   287→        {
   288→            _balances.TryGetValue(address, out var bal);
   289→            return Task.FromResult(bal);
   290→        }
   291→
   292→        public async Task CommitAsync()
   293→        {
   294→            foreach (var (addr, bal) in _balances)
   295→            {
   296→                await _repository.PersistBalanceAsync(_descriptor.TokenId, addr, bal, CancellationToken.None);
   297→            }
   298→        }
   299→
   300→        public void Dispose()
   301→        {
   302→            // Commit pending balances on dispose for safety.
   303→            CommitAsync().GetAwaiter().GetResult();
   304→        }
   305→    }
