#### 4.3.2 RabbitMQ Implementation (Partial)

```csharp
// src/UtilityChain.Core/Services/RabbitMQMessageBroker.cs
namespace UtilityChain.Core.Services;

public sealed class RabbitMQMessageBroker : IMessageBroker
{
    private readonly IConnection _connection;
    private readonly IModel _publishChannel;
    private readonly ILogger<RabbitMQMessageBroker> _logger;
    private readonly MessageBrokerOptions _options;
    private readonly AsyncPolicy _retryPolicy;
    private readonly ConcurrentDictionary<string, IModel> _consumerChannels = new();

    public RabbitMQMessageBroker(
        IOptions<MessageBrokerOptions> options,
        ILogger<RabbitMQMessageBroker> logger)
    {
        _options = options.Value;
        _logger = logger;

        // Build resilience policy using Polly
        _retryPolicy = Policy
            .Handle<BrokerUnreachableException>()
            .Or<SocketException>()
            .WaitAndRetryAsync(
                _options.Resilience.RetryPolicy.MaxRetries,
                retryAttempt => TimeSpan.FromMilliseconds(
                    Math.Min(
                        _options.Resilience.RetryPolicy.InitialDelayMs *
                        Math.Pow(_options.Resilience.RetryPolicy.BackoffMultiplier, retryAttempt),
                        _options.Resilience.RetryPolicy.MaxDelayMs)),
                (ex, timeSpan, retryCount, ctx) =>
                {
                    _logger.LogWarning(ex,
                        "RabbitMQ connection failed. Retry {RetryCount} in {Delay}ms",
                        retryCount, timeSpan.TotalMilliseconds);
                });

        _connection = CreateConnection();
        _publishChannel = _connection.CreateModel();

        DeclareTopology();
    }

    private IConnection CreateConnection()
    {
        var factory = new ConnectionFactory
        {
            HostName = _options.Connection.Host,
            Port = _options.Connection.Port,
            VirtualHost = _options.Connection.VirtualHost,
            UserName = _options.Connection.Username,
            Password = _options.Connection.Password,
            RequestedHeartbeat = TimeSpan.FromSeconds(_options.Connection.HeartbeatIntervalSeconds),
            AutomaticRecoveryEnabled = true,
            NetworkRecoveryInterval = TimeSpan.FromSeconds(10),
            DispatchConsumersAsync = true
        };

        return factory.CreateConnection();
    }

    private void DeclareTopology()
    {
        // Main exchange
        _publishChannel.ExchangeDeclare(
            exchange: _options.Exchange.Name,
            type: _options.Exchange.Type,
            durable: _options.Exchange.Durable,
            autoDelete: _options.Exchange.AutoDelete);

        // Dead letter exchange
        _publishChannel.ExchangeDeclare(
            exchange: _options.Queues.DeadLetterExchange,
            type: ExchangeType.Direct,
            durable: true);
    }

    public async ValueTask PublishAsync<TEvent>(
        TEvent @event,
        string? correlationId = null,
        CancellationToken ct = default) where TEvent : class, IEvent
    {
        var routingKey = GetRoutingKey<TEvent>();
        var body = JsonSerializer.SerializeToUtf8Bytes(@event);

        var properties = _publishChannel.CreateBasicProperties();
        properties.ContentType = "application/json";
        properties.DeliveryMode = 2; // persistent
        properties.MessageId = Guid.NewGuid().ToString();
        properties.Timestamp = new AmqpTimestamp(DateTimeOffset.UtcNow.ToUnixTimeSeconds());
        properties.Type = typeof(TEvent).FullName;

        if (correlationId != null)
            properties.CorrelationId = correlationId;

        await _retryPolicy.ExecuteAsync(async () =>
        {
            _publishChannel.BasicPublish(
                exchange: _options.Exchange.Name,
                routingKey: routingKey,
                basicProperties: properties,
                body: body);

            _logger.LogDebug("Published {EventType} to {RoutingKey}",
                typeof(TEvent).Name, routingKey);
        });
    }

    public IDisposable Subscribe<TEvent>(
        Func<TEvent, CancellationToken, ValueTask> handler,
        string subscriptionId,
        SubscriptionOptions? options = null) where TEvent : class, IEvent
    {
        options ??= new SubscriptionOptions();
        var queueName = $"utilitychain.{typeof(TEvent).Name}.{subscriptionId}";
        var routingKey = GetRoutingKey<TEvent>();

        var channel = _connection.CreateModel();
        _consumerChannels[queueName] = channel;

        // Declare queue with DLQ
        var queueArgs = new Dictionary<string, object>
        {
            ["x-dead-letter-exchange"] = _options.Queues.DeadLetterExchange,
            ["x-dead-letter-routing-key"] = $"dlq.{queueName}"
        };

        channel.QueueDeclare(
            queue: queueName,
            durable: true,
            exclusive: false,
            autoDelete: false,
            arguments: queueArgs);

        channel.QueueBind(queueName, _options.Exchange.Name, routingKey);
        channel.BasicQos(0, (ushort)options.PrefetchCount, false);

        var consumer = new AsyncEventingBasicConsumer(channel);
        consumer.Received += async (_, ea) =>
        {
            try
            {
                var @event = JsonSerializer.Deserialize<TEvent>(ea.Body.Span)!;
                await handler(@event, CancellationToken.None);
                channel.BasicAck(ea.DeliveryTag, false);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error processing {EventType}", typeof(TEvent).Name);
                channel.BasicNack(ea.DeliveryTag, false, false); // Send to DLQ
            }
        };

        channel.BasicConsume(queueName, false, consumer);

        return new SubscriptionHandle(() =>
        {
            channel.Close();
            _consumerChannels.TryRemove(queueName, out _);
        });
    }

    private static string GetRoutingKey<TEvent>() => typeof(TEvent).FullName!.ToLowerInvariant();

    public BrokerHealthStatus GetHealthStatus()
    {
        return _connection.IsOpen ? BrokerHealthStatus.Healthy : BrokerHealthStatus.Unhealthy;
    }

    public async ValueTask DisposeAsync()
    {
        foreach (var channel in _consumerChannels.Values)
            channel.Close();

        _publishChannel.Close();
        _connection.Close();
    }

    private sealed class SubscriptionHandle : IDisposable
    {
        private readonly Action _disposeAction;
        public SubscriptionHandle(Action disposeAction) => _disposeAction = disposeAction;
        public void Dispose() => _disposeAction();
    }
}
```

