### 5.3 Retry Policy Configuration (Polly)

```csharp
// Applied to both publishing and consuming
services.AddSingleton<IAsyncPolicy>(sp =>
{
    var options = sp.GetRequiredService<IOptions<MessageBrokerOptions>>().Value;

    var retryPolicy = Policy
        .Handle<BrokerUnreachableException>()
        .Or<AlreadyClosedException>()
        .WaitAndRetryAsync(
            options.Resilience.RetryPolicy.MaxRetries,
            retryAttempt => TimeSpan.FromMilliseconds(
                options.Resilience.RetryPolicy.InitialDelayMs *
                Math.Pow(options.Resilience.RetryPolicy.BackoffMultiplier, retryAttempt)));

    var circuitBreaker = Policy
        .Handle<BrokerUnreachableException>()
        .CircuitBreakerAsync(
            exceptionsAllowedBeforeBreaking: options.Resilience.CircuitBreaker.FailureThreshold,
            durationOfBreak: TimeSpan.FromSeconds(options.Resilience.CircuitBreaker.BreakDurationSeconds),
            onBreak: (ex, duration) =>
                Log.Warning("Circuit breaker opened for {Duration}s due to {Exception}",
                           duration.TotalSeconds, ex.GetType().Name),
            onReset: () => Log.Information("Circuit breaker reset"),
            onHalfOpen: () => Log.Information("Circuit breaker half-open"));

    return Policy.WrapAsync(retryPolicy, circuitBreaker);
});
```

### 5.4 Idempotent Handler Pattern

To handle duplicate message delivery:

```csharp
public class IdempotentEventHandler<TEvent> : IEventHandler<TEvent>
    where TEvent : class, IEvent
{
    private readonly IEventHandler<TEvent> _inner;
    private readonly IProcessedEventStore _processedStore;
    private readonly ILogger _logger;

    public async ValueTask HandleAsync(TEvent @event, CancellationToken ct)
    {
        var eventId = GetEventId(@event);

        if (await _processedStore.HasBeenProcessedAsync(eventId, ct))
        {
            _logger.LogDebug("Event {EventId} already processed, skipping", eventId);
            return;
        }

        await _inner.HandleAsync(@event, ct);
        await _processedStore.MarkAsProcessedAsync(eventId, ct);
    }

    private static string GetEventId(TEvent @event) =>
        @event switch
        {
            IHasEventId e => e.EventId.ToString(),
            _ => @event.GetHashCode().ToString()
        };
}
